  1→/**
  2→ * Graph scan: periodic workspace-wide analysis for contradictions and anomalies.
  3→ *
  4→ * Pure query functions that gather scan signals from the workspace graph,
  5→ * then delegate to the observer agent for contradiction analysis.
  6→ *
  7→ * Scan types:
  8→ *   1. Decision-implementation contradictions: confirmed decisions vs completed tasks
  9→ *   2. Stale blocked tasks: tasks blocked longer than threshold (14 days)
 10→ */
 11→
 12→import { RecordId, type Surreal } from "surrealdb";
 13→import type { LanguageModel } from "ai";
 14→import { createObservation, listWorkspaceOpenObservations, type ObserveTargetRecord } from "../observation/queries";
 15→import { logInfo } from "../http/observability";
 16→import { detectContradictions, synthesizePatterns, type Anomaly } from "./llm-synthesis";
 17→import { parseEntityRef } from "./evidence-validator";
 18→
 19→// ---------------------------------------------------------------------------
 20→// Types
 21→// ---------------------------------------------------------------------------
 22→
 23→export type ConfirmedDecision = {
 24→  id: RecordId<"decision">;
 25→  summary: string;
 26→  rationale?: string;
 27→};
 28→
 29→export type CompletedTask = {
 30→  id: RecordId<"task">;
 31→  title: string;
 32→  description?: string;
 33→};
 34→
 35→export type StaleBlockedTask = {
 36→  id: RecordId<"task">;
 37→  title: string;
 38→  description?: string;
 39→  updated_at: string | Date;
 40→  daysBlocked: number;
 41→};
 42→
 43→export type StatusDriftTask = {
 44→  id: RecordId<"task">;
 45→  title: string;
 46→  status: string;
 47→  dependency: {
 48→    id: RecordId<"task">;
 49→    title: string;
 50→    status: string;
 51→  };
 52→};
 53→
 54→export type GraphScanResult = {
 55→  contradictions_found: number;
 56→  stale_blocked_found: number;
 57→  status_drift_found: number;
 58→  observations_created: number;
 59→};
 60→
 61→// ---------------------------------------------------------------------------
 62→// Configuration
 63→// ---------------------------------------------------------------------------
 64→
 65→const STALE_BLOCKED_THRESHOLD_DAYS = 14;
 66→
 67→// ---------------------------------------------------------------------------
 68→// Graph queries (pure data gathering)
 69→// ---------------------------------------------------------------------------
 70→
 71→async function queryConfirmedDecisions(
 72→  surreal: Surreal,
 73→  workspaceRecord: RecordId<"workspace", string>,
 74→): Promise<ConfirmedDecision[]> {
 75→  const [rows] = await surreal.query<[ConfirmedDecision[]]>(
 76→    `SELECT id, summary, rationale, created_at FROM decision
 77→     WHERE workspace = $ws AND status = "confirmed"
 78→     ORDER BY created_at DESC
 79→     LIMIT 50;`,
 80→    { ws: workspaceRecord },
 81→  );
 82→  return rows ?? [];
 83→}
 84→
 85→async function queryCompletedTasks(
 86→  surreal: Surreal,
 87→  workspaceRecord: RecordId<"workspace", string>,
 88→): Promise<CompletedTask[]> {
 89→  const [rows] = await surreal.query<[CompletedTask[]]>(
 90→    `SELECT id, title, description, updated_at FROM task
 91→     WHERE workspace = $ws AND status IN ["completed", "done"]
 92→     ORDER BY updated_at DESC
 93→     LIMIT 50;`,
 94→    { ws: workspaceRecord },
 95→  );
 96→  return rows ?? [];
 97→}
 98→
 99→async function queryStaleBlockedTasks(
100→  surreal: Surreal,
101→  workspaceRecord: RecordId<"workspace", string>,
102→): Promise<StaleBlockedTask[]> {
103→  const thresholdDate = new Date(
104→    Date.now() - STALE_BLOCKED_THRESHOLD_DAYS * 24 * 60 * 60 * 1000,
105→  );
106→
107→  const [rows] = await surreal.query<
108→    [Array<{ id: RecordId<"task">; title: string; description?: string; updated_at: string }>]
109→  >(
110→    `SELECT id, title, description, updated_at FROM task
111→     WHERE workspace = $ws
112→       AND status = "blocked"
113→       AND updated_at < $threshold
114→     ORDER BY updated_at ASC
115→     LIMIT 50;`,
116→    { ws: workspaceRecord, threshold: thresholdDate },
117→  );
118→
119→  return (rows ?? []).map((row) => {
120→    const updatedAt = new Date(row.updated_at);
121→    const daysBlocked = Math.floor(
122→      (Date.now() - updatedAt.getTime()) / (24 * 60 * 60 * 1000),
123→    );
124→    return { ...row, daysBlocked };
125→  });
126→}
127→
128→async function queryStatusDriftTasks(
129→  surreal: Surreal,
130→  workspaceRecord: RecordId<"workspace", string>,
131→): Promise<StatusDriftTask[]> {
132→  // Two-step approach: first find completed tasks with dependencies,
133→  // then filter for incomplete dependencies in application code
134→  const [rows] = await surreal.query<[Array<{
135→    id: RecordId<"task">;
136→    title: string;
137→    status: string;
138→    dep_ids: RecordId<"task">[];
139→    dep_titles: string[];
140→    dep_statuses: string[];
141→  }>]>(
142→    `SELECT
143→       id, title, status,
144→       ->depends_on->task.id AS dep_ids,
145→       ->depends_on->task.title AS dep_titles,
146→       ->depends_on->task.status AS dep_statuses
147→     FROM task
148→     WHERE workspace = $ws
149→       AND status IN ["completed", "done"]
150→       AND array::len(->depends_on->task) > 0
151→     LIMIT 50;`,
152→    { ws: workspaceRecord },
153→  );
154→
155→  return (rows ?? []).flatMap((row) => {
156→    const depIds = row.dep_ids ?? [];
157→    const depTitles = row.dep_titles ?? [];
158→    const depStatuses = row.dep_statuses ?? [];
159→
160→    const drifts: StatusDriftTask[] = [];
161→    for (let i = 0; i < depIds.length; i++) {
162→      const depStatus = depStatuses[i];
163→      if (depStatus !== "completed" && depStatus !== "done") {
164→        drifts.push({
165→          id: row.id,
166→          title: row.title,
167→          status: row.status,
168→          dependency: {
169→            id: depIds[i],
170→            title: depTitles[i],
171→            status: depStatus,
172→          },
173→        });
174→      }
175→    }
176→    return drifts;
177→  });
178→}
179→
180→// ---------------------------------------------------------------------------
181→// Entity-level deduplication query
182→// ---------------------------------------------------------------------------
183→
184→/**
185→ * Queries existing open observer observations linked to a specific entity.
186→ * Used for entity-level dedup -- if the observer already has an open observation
187→ * on this entity, we skip creating another.
188→ */
189→// Static query map: one pre-built query string per allowed table, eliminating
190→// dynamic interpolation at the call site (prevents SurrealQL injection).
191→const OBSERVER_DEDUP_QUERIES: Record<string, string> = Object.fromEntries(
192→  ["project", "feature", "task", "decision", "question", "intent", "git_commit", "observation"].map(
193→    (table) => [
194→      table,
195→      `SELECT text, severity, status FROM observation
196→       WHERE workspace = $ws
197→         AND source_agent = "observer_agent"
198→         AND status IN ["open", "acknowledged"]
199→         AND ->observes->${table}.id CONTAINS $entity
200→       LIMIT 20;`,
201→    ],
202→  ),
203→);
204→
205→async function queryExistingObserverObservationsForEntity(
206→  surreal: Surreal,
207→  workspaceRecord: RecordId<"workspace", string>,
208→  entityRecord: RecordId<string, string>,
209→): Promise<Array<{ text: string; severity: string; status: string }>> {
210→  const query = OBSERVER_DEDUP_QUERIES[entityRecord.table.name];
211→  if (!query) {
212→    throw new Error(`Invalid entity table for observer dedup query: ${entityRecord.table.name}`);
213→  }
214→
215→  const [rows] = await surreal.query<[Array<{ text: string; severity: string; status: string }>]>(
216→    query,
217→    { ws: workspaceRecord, entity: entityRecord },
218→  );
219→  return rows ?? [];
220→}
221→
222→// ---------------------------------------------------------------------------
223→// Deduplication
224→// ---------------------------------------------------------------------------
225→
226→type ExistingObservation = {
227→  text: string;
228→  severity: string;
229→  status: string;
230→};
231→
232→function isAlreadyObserved(
233→  existingObservations: ExistingObservation[],
234→  newText: string,
235→  entityId?: string,
236→): boolean {
237→  const normalizedNew = newText.toLowerCase();
238→
239→  return existingObservations.some((obs) => {
240→    if (obs.status === "resolved") return false;
241→
242→    // When entity ID is available, require it to appear in the existing text
243→    // so observations about different entities are never considered duplicates
244→    if (entityId && !obs.text.toLowerCase().includes(entityId.toLowerCase())) {
245→      return false;
246→    }
247→
248→    const normalizedExisting = obs.text.toLowerCase();
249→    // Check if the core issue is already covered using a meaningful prefix
250→    const prefixLen = Math.min(80, normalizedNew.length);
251→    return (
252→      normalizedExisting.includes(normalizedNew.slice(0, prefixLen)) ||
253→      normalizedNew.includes(normalizedExisting.slice(0, prefixLen))
254→    );
255→  });
256→}
257→
258→// ---------------------------------------------------------------------------
259→// Scan orchestrator
260→// ---------------------------------------------------------------------------
261→
262→export async function runGraphScan(
263→  surreal: Surreal,
264→  workspaceRecord: RecordId<"workspace", string>,
265→  observerModel: LanguageModel,
266→): Promise<GraphScanResult> {
267→  const result: GraphScanResult = {
268→    contradictions_found: 0,
269→    stale_blocked_found: 0,
270→    status_drift_found: 0,
271→    observations_created: 0,
272→  };
273→
274→  // Load existing observations for deduplication
275→  const existingObservations = await listWorkspaceOpenObservations({
276→    surreal,
277→    workspaceRecord,
278→    limit: 100,
279→  });
280→
281→  // 1. Detect decision-implementation contradictions (LLM-based)
282→  const [decisions, completedTasks] = await Promise.all([
283→    queryConfirmedDecisions(surreal, workspaceRecord),
284→    queryCompletedTasks(surreal, workspaceRecord),
285→  ]);
286→
287→  type ContradictionPair = { decision: ConfirmedDecision; task: CompletedTask };
288→  const contradictions: ContradictionPair[] = [];
289→
290→  if (decisions.length > 0 && completedTasks.length > 0) {
291→    const decisionMap = new Map(decisions.map((d) => [d.id.id as string, d]));
292→    const taskMap = new Map(completedTasks.map((t) => [t.id.id as string, t]));
293→
294→    const detected = await detectContradictions(
295→      observerModel,
296→      decisions.map((d) => ({ id: d.id.id as string, summary: d.summary, rationale: d.rationale })),
297→      completedTasks.map((t) => ({ id: t.id.id as string, title: t.title, description: t.description })),
298→    );
299→
300→    if (detected) {
301→      for (const c of detected) {
302→        const decisionId = parseEntityRef(c.decision_ref)?.id;
303→        const taskId = parseEntityRef(c.task_ref)?.id;
304→        const decision = decisionId ? decisionMap.get(decisionId) : undefined;
305→        const task = taskId ? taskMap.get(taskId) : undefined;
306→        if (decision && task) contradictions.push({ decision, task });
307→      }
308→    }
309→  }
310→
311→  result.contradictions_found = contradictions.length;
312→
313→  for (const { decision, task } of contradictions) {
314→    // Entity-level dedup: check if observer already has an open observation on this decision
315→    const existingForDecision = await queryExistingObserverObservationsForEntity(
316→      surreal, workspaceRecord,
317→      decision.id as RecordId<string, string>,
318→    );
319→
320→    const observationText =
321→      `Contradiction detected: Decision "${decision.summary}" conflicts with completed task "${task.title}". ` +
322→      `The task appears to implement an approach that contradicts the confirmed decision.`;
323→
324→    if (existingForDecision.length > 0 || isAlreadyObserved(existingObservations, observationText, decision.id.id as string)) {
325→      logInfo("observer.scan.dedup", "Skipping duplicate contradiction observation", {
326→        decisionId: decision.id.id,
327→        taskId: task.id.id,
328→      });
329→      continue;
330→    }
331→
332→    const now = new Date();
333→    await createObservation({
334→      surreal,
335→      workspaceRecord,
336→      text: observationText,
337→      severity: "conflict",
338→      sourceAgent: "observer_agent",
339→      observationType: "contradiction",
340→      now,
341→      relatedRecord: decision.id as RecordId<"project" | "feature" | "task" | "decision" | "question", string>,
342→    });
343→
344→    result.observations_created += 1;
345→  }
346→
347→  // 2. Detect stale blocked tasks
348→  const staleBlocked = await queryStaleBlockedTasks(surreal, workspaceRecord);
349→  result.stale_blocked_found = staleBlocked.length;
350→
351→  for (const task of staleBlocked) {
352→    // Entity-level dedup: check if observer already has an open observation on this task
353→    const existingForTask = await queryExistingObserverObservationsForEntity(
354→      surreal, workspaceRecord,
355→      task.id as RecordId<string, string>,
356→    );
357→
358→    const observationText =
359→      `Task blocked for ${task.daysBlocked} days: "${task.title}". ` +
360→      `This task has been blocked since ${new Date(task.updated_at).toISOString().slice(0, 10)} ` +
361→      `(exceeds the ${STALE_BLOCKED_THRESHOLD_DAYS}-day threshold).`;
362→
363→    if (existingForTask.length > 0 || isAlreadyObserved(existingObservations, observationText, task.id.id as string)) {
364→      logInfo("observer.scan.dedup", "Skipping duplicate stale-blocked observation", {
365→        taskId: task.id.id,
366→      });
367→      continue;
368→    }
369→
370→    const now = new Date();
371→    await createObservation({
372→      surreal,
373→      workspaceRecord,
374→      text: observationText,
375→      severity: "warning",
376→      sourceAgent: "observer_agent",
377→      observationType: "anomaly",
378→      now,
379→      relatedRecord: task.id as RecordId<"project" | "feature" | "task" | "decision" | "question", string>,
380→    });
381→
382→    result.observations_created += 1;
383→  }
384→
385→  // 3. Detect status drift (completed tasks with incomplete dependencies)
386→  const driftTasks = await queryStatusDriftTasks(surreal, workspaceRecord);
387→  result.status_drift_found = driftTasks.length;
388→
389→  for (const drift of driftTasks) {
390→    // Entity-level dedup
391→    const existingForTask = await queryExistingObserverObservationsForEntity(
392→      surreal, workspaceRecord,
393→      drift.id as RecordId<string, string>,
394→    );
395→
396→    const observationText =
397→      `Status drift detected: Task "${drift.title}" is marked as ${drift.status}, ` +
398→      `but its dependency "${drift.dependency.title}" is still ${drift.dependency.status}. ` +
399→      `A task should not be completed before its dependencies.`;
400→
401→    if (existingForTask.length > 0 || isAlreadyObserved(existingObservations, observationText, drift.id.id as string)) {
402→      logInfo("observer.scan.dedup", "Skipping duplicate status-drift observation", {
403→        taskId: drift.id.id,
404→        depTaskId: drift.dependency.id.id,
405→      });
406→      continue;
407→    }
408→
409→    const now = new Date();
410→    await createObservation({
411→      surreal,
412→      workspaceRecord,
413→      text: observationText,
414→      severity: "warning",
415→      sourceAgent: "observer_agent",
416→      observationType: "anomaly",
417→      now,
418→      relatedRecord: drift.id as RecordId<"project" | "feature" | "task" | "decision" | "question", string>,
419→    });
420→
421→    result.observations_created += 1;
422→  }
423→
424→  // 4. LLM pattern synthesis
425→  const anomalies: Anomaly[] = [];
426→
427→  for (const { decision, task } of contradictions) {
428→    anomalies.push({
429→      type: "contradiction",
430→      text: `Decision "${decision.summary}" conflicts with task "${task.title}"`,
431→      entityId: decision.id.id as string,
432→      entityTable: "decision",
433→    });
434→  }
435→  for (const task of staleBlocked) {
436→    anomalies.push({
437→      type: "stale_blocked",
438→      text: `Task "${task.title}" blocked for ${task.daysBlocked} days`,
439→      entityId: task.id.id as string,
440→      entityTable: "task",
441→    });
442→  }
443→  for (const drift of driftTasks) {
444→    anomalies.push({
445→      type: "status_drift",
446→      text: `Task "${drift.title}" completed but dependency "${drift.dependency.title}" is ${drift.dependency.status}`,
447→      entityId: drift.id.id as string,
448→      entityTable: "task",
449→    });
450→  }
451→
452→  if (anomalies.length > 0) {
453→    const patterns = await synthesizePatterns(observerModel, anomalies);
454→
455→    if (patterns) {
456→      for (const pattern of patterns) {
457→        // Dedup: check if a similar pattern observation already exists
458→        const patternText = `${pattern.pattern_name}: ${pattern.description}`;
459→        if (isAlreadyObserved(existingObservations, patternText)) {
460→          logInfo("observer.scan.synthesis_dedup", "Skipping duplicate pattern", {
461→            pattern: pattern.pattern_name,
462→          });
463→          continue;
464→        }
465→
466→        // Build related records from contributing entities
467→        const relatedRecords: ObserveTargetRecord[] = [];
468→        for (const ref of pattern.contributing_entities) {
469→          const parsed = parseEntityRef(ref);
470→          if (parsed) {
471→            relatedRecords.push(new RecordId(parsed.table, parsed.id) as ObserveTargetRecord);
472→          }
473→        }
474→
475→        const now = new Date();
476→        await createObservation({
477→          surreal,
478→          workspaceRecord,
479→          text: patternText,
480→          severity: pattern.severity,
481→          sourceAgent: "observer_agent",
482→          observationType: "pattern",
483→          now,
484→          relatedRecords: relatedRecords.length > 0 ? relatedRecords : undefined,
485→        });
486→
487→        result.observations_created += 1;
488→      }
489→
490→      logInfo("observer.scan.synthesis", "Pattern synthesis completed", {
491→        patternsFound: patterns.length,
492→      });
493→    } else {
494→      logInfo("observer.llm.fallback", "Pattern synthesis failed, anomalies reported individually", {
495→        anomalyCount: anomalies.length,
496→      });
497→    }
498→  }
499→
500→  logInfo("observer.scan.completed", "Graph scan completed", {
501→    workspaceId: workspaceRecord.id,
502→    ...result,
503→  });
504→
505→  return result;
506→}
