  1→/**
  2→ * LLM synthesis: effect boundary for generateObject calls in pattern synthesis pipeline.
  3→ *
  4→ * Takes anomalies from deterministic graph scan and synthesizes named patterns.
  5→ * Uses AbortSignal.timeout(10_000) for latency control.
  6→ * Returns undefined on any failure.
  7→ */
  8→
  9→import { generateObject, type LanguageModel } from "ai";
 10→import { logError, logInfo } from "../http/observability";
 11→import { contradictionDetectionResultSchema, synthesisResultSchema, type DetectedContradiction, type SynthesisPattern } from "./schemas";
 12→
 13→export type Anomaly = {
 14→  type: "contradiction" | "stale_blocked" | "status_drift";
 15→  text: string;
 16→  entityId: string;
 17→  entityTable: string;
 18→};
 19→
 20→/**
 21→ * Synthesizes anomalies into named patterns via LLM.
 22→ * Returns patterns with min 2 contributing entities, or undefined on failure.
 23→ */
 24→export async function synthesizePatterns(
 25→  model: LanguageModel,
 26→  anomalies: Anomaly[],
 27→): Promise<SynthesisPattern[] | undefined> {
 28→  if (anomalies.length === 0) return [];
 29→
 30→  const start = Date.now();
 31→
 32→  // Partition large workspaces: top 20 per type
 33→  const partitioned = partitionAnomalies(anomalies, 20);
 34→
 35→  try {
 36→    const anomaliesText = partitioned.map((a) =>
 37→      `- [${a.entityTable}:${a.entityId}] (${a.type}) ${a.text}`,
 38→    ).join("\n");
 39→
 40→    const result = await generateObject({
 41→      model,
 42→      schema: synthesisResultSchema,
 43→      prompt: `You are a pattern synthesis agent analyzing workspace anomalies to identify systemic patterns.
 44→
 45→## Anomalies Detected
 46→${anomaliesText}
 47→
 48→## Instructions
 49→Analyze these anomalies and identify higher-level patterns:
 50→- "bottleneck_decision" = single decision blocking multiple tasks
 51→- "cascade_block" = chain of blocked items
 52→- "priority_drift" = priorities inconsistent with actions
 53→- "stale_cluster" = group of stale items in same area
 54→- "contradiction_cluster" = multiple contradictions sharing a root cause
 55→
 56→Rules:
 57→- Each pattern MUST reference at least 2 contributing entities using table:id format
 58→- Only include entities from the anomalies listed above
 59→- If no meaningful patterns emerge, return an empty patterns array
 60→- Set severity to "conflict" only for active contradictions`,
 61→      abortSignal: AbortSignal.timeout(10_000),
 62→    });
 63→
 64→    const latencyMs = Date.now() - start;
 65→    logInfo("observer.llm.synthesis", "LLM pattern synthesis completed", {
 66→      latencyMs,
 67→      patternCount: result.object.patterns.length,
 68→    });
 69→
 70→    // Filter patterns with < 2 contributing entities (schema enforces min 2, but defense in depth)
 71→    return result.object.patterns.filter((p) => p.contributing_entities.length >= 2);
 72→  } catch (error) {
 73→    const latencyMs = Date.now() - start;
 74→    logError("observer.llm.synthesis_error", "LLM pattern synthesis failed", {
 75→      error,
 76→      latencyMs,
 77→    });
 78→    return undefined;
 79→  }
 80→}
 81→
 82→// ---------------------------------------------------------------------------
 83→// Contradiction detection (LLM-based)
 84→// ---------------------------------------------------------------------------
 85→
 86→export type DecisionInput = {
 87→  id: string;
 88→  summary: string;
 89→  rationale?: string;
 90→};
 91→
 92→export type TaskInput = {
 93→  id: string;
 94→  title: string;
 95→  description?: string;
 96→};
 97→
 98→/**
 99→ * Detects contradictions between confirmed decisions and completed tasks via LLM.
100→ * Returns detected contradiction pairs, or undefined on failure.
101→ */
102→export async function detectContradictions(
103→  model: LanguageModel,
104→  decisions: DecisionInput[],
105→  tasks: TaskInput[],
106→): Promise<DetectedContradiction[] | undefined> {
107→  if (decisions.length === 0 || tasks.length === 0) return [];
108→
109→  const start = Date.now();
110→
111→  try {
112→    const decisionsText = decisions.map((d) =>
113→      `- [decision:${d.id}] ${d.summary}${d.rationale ? ` (rationale: ${d.rationale})` : ""}`,
114→    ).join("\n");
115→
116→    const tasksText = tasks.map((t) =>
117→      `- [task:${t.id}] ${t.title}${t.description ? ` — ${t.description}` : ""}`,
118→    ).join("\n");
119→
120→    const result = await generateObject({
121→      model,
122→      schema: contradictionDetectionResultSchema,
123→      prompt: `You are an observer agent scanning a workspace knowledge graph for contradictions between confirmed decisions and completed tasks.
124→
125→## Confirmed Decisions
126→${decisionsText}
127→
128→## Completed Tasks
129→${tasksText}
130→
131→## Instructions
132→Identify any completed task that contradicts a confirmed decision. A contradiction means the task implements an approach that directly conflicts with what the decision mandates.
133→
134→Examples of contradictions:
135→- Decision mandates tRPC but task implements REST endpoints
136→- Decision requires TypeScript but task delivers JavaScript
137→- Decision specifies PostgreSQL but task sets up MongoDB
138→- Decision requires feature flags but task ships without them
139→
140→Rules:
141→- Only flag clear, direct contradictions — not minor implementation variations
142→- Use the exact table:id format from the lists above for decision_ref and task_ref
143→- If no contradictions exist, return an empty array`,
144→      abortSignal: AbortSignal.timeout(10_000),
145→    });
146→
147→    const latencyMs = Date.now() - start;
148→    logInfo("observer.llm.contradiction_detection", "LLM contradiction detection completed", {
149→      latencyMs,
150→      contradictionCount: result.object.contradictions.length,
151→    });
152→
153→    return result.object.contradictions;
154→  } catch (error) {
155→    const latencyMs = Date.now() - start;
156→    logError("observer.llm.contradiction_detection_error", "LLM contradiction detection failed", {
157→      error,
158→      latencyMs,
159→    });
160→    return undefined;
161→  }
162→}
163→
164→/**
165→ * Partitions anomalies by type and takes top N per type to manage LLM context size.
166→ */
167→function partitionAnomalies(anomalies: Anomaly[], maxPerType: number): Anomaly[] {
168→  if (anomalies.length <= maxPerType * 3) return anomalies;
169→
170→  const byType = new Map<string, Anomaly[]>();
171→  for (const a of anomalies) {
172→    const list = byType.get(a.type) ?? [];
173→    list.push(a);
174→    byType.set(a.type, list);
175→  }
176→
177→  const result: Anomaly[] = [];
178→  for (const [, list] of byType) {
179→    result.push(...list.slice(0, maxPerType));
180→  }
181→  return result;
182→}
