 1→/**
 2→ * Evidence validator: pure core function to strip invalid entity refs from LLM output.
 3→ *
 4→ * Pure module — no IO imports. Takes LLM output + valid entity set, returns cleaned output.
 5→ */
 6→
 7→const VALID_TABLES = new Set([
 8→  "project", "feature", "task", "decision", "question",
 9→  "observation", "intent", "git_commit",
10→]);
11→
12→/**
13→ * Parses a "table:id" string into its components.
14→ * Returns undefined if the format is invalid or the table is not in the allowlist.
15→ */
16→export function parseEntityRef(ref: string): { table: string; id: string } | undefined {
17→  const colonIndex = ref.indexOf(":");
18→  if (colonIndex < 1) return undefined;
19→
20→  const table = ref.slice(0, colonIndex);
21→  const id = ref.slice(colonIndex + 1);
22→
23→  if (!VALID_TABLES.has(table) || id.length === 0) return undefined;
24→
25→  return { table, id };
26→}
27→
28→/**
29→ * Strips entity references that don't exist in the provided valid entity set.
30→ *
31→ * @param refs - Array of "table:id" strings from LLM output
32→ * @param validEntityIds - Set of "table:id" strings known to exist in the workspace
33→ * @returns Filtered array containing only valid, existing references
34→ */
35→export function validateEvidenceRefs(
36→  refs: string[],
37→  validEntityIds: Set<string>,
38→): string[] {
39→  return refs.filter((ref) => {
40→    const parsed = parseEntityRef(ref);
41→    if (!parsed) return false;
42→    return validEntityIds.has(ref);
43→  });
44→}
