  1→/**
  2→ * Observer agent: verifies entity state changes and surfaces observations.
  3→ *
  4→ * Owns the full verification pipeline: deterministic + LLM reasoning.
  5→ * Called by observer-route.ts (HTTP adapter) for each entity event.
  6→ *
  7→ * Pipeline: receive event -> gather signals -> deterministic verdict
  8→ *           -> (optional) LLM reasoning -> persist observation
  9→ */
 10→
 11→import { RecordId, type Surreal } from "surrealdb";
 12→import type { LanguageModel } from "ai";
 13→import { createObservation, type ObserveTargetRecord } from "../../observation/queries";
 14→import { logInfo } from "../../http/observability";
 15→import { gatherTaskSignals } from "../../observer/external-signals";
 16→import { checkCiStatus } from "../../observer/external-signals";
 17→import {
 18→  compareTaskCompletion,
 19→  compareIntentCompletion,
 20→  compareCommitStatus,
 21→  compareDecisionConfirmation,
 22→  compareObservationPeerReview,
 23→  shouldSkipLlm,
 24→  applyLlmVerdict,
 25→  type VerificationResult,
 26→  type IntentSignals,
 27→  type DecisionSignals,
 28→  type ObservationPeerReviewSignals,
 29→} from "../../observer/verification-pipeline";
 30→import { buildEntityContext } from "../../observer/context-loader";
 31→import { generateVerificationVerdict, generatePeerReviewVerdict } from "../../observer/llm-reasoning";
 32→import { parseEntityRef } from "../../observer/evidence-validator";
 33→
 34→// ---------------------------------------------------------------------------
 35→// Types
 36→// ---------------------------------------------------------------------------
 37→
 38→export type ObserverVerdict = "match" | "mismatch" | "inconclusive";
 39→
 40→export type ObserverAgentOutput = {
 41→  observations_created: number;
 42→  verdict: ObserverVerdict;
 43→  evidence: string[];
 44→};
 45→
 46→export type ObserverAgentInput = {
 47→  surreal: Surreal;
 48→  workspaceRecord: RecordId<"workspace", string>;
 49→  entityTable: string;
 50→  entityId: string;
 51→  entityBody?: Record<string, unknown>;
 52→  observerModel?: LanguageModel;
 53→};
 54→
 55→// ---------------------------------------------------------------------------
 56→// Agent entry point
 57→// ---------------------------------------------------------------------------
 58→
 59→export async function runObserverAgent(input: ObserverAgentInput): Promise<ObserverAgentOutput> {
 60→  const { entityTable } = input;
 61→
 62→  switch (entityTable) {
 63→    case "task":
 64→      return verifyTask(input);
 65→    case "intent":
 66→      return verifyIntent(input);
 67→    case "git_commit":
 68→      return verifyCommit(input);
 69→    case "decision":
 70→      return verifyDecision(input);
 71→    case "observation":
 72→      return peerReviewObservation(input);
 73→    default:
 74→      return {
 75→        observations_created: 0,
 76→        verdict: "inconclusive",
 77→        evidence: [`Entity type '${entityTable}' verification not yet implemented`],
 78→      };
 79→  }
 80→}
 81→
 82→// ---------------------------------------------------------------------------
 83→// Task verification (deterministic + LLM)
 84→// ---------------------------------------------------------------------------
 85→
 86→async function verifyTask(input: ObserverAgentInput): Promise<ObserverAgentOutput> {
 87→  const { surreal, workspaceRecord, entityId: taskId, entityBody: body, observerModel } = input;
 88→  const taskRecord = new RecordId("task", taskId);
 89→  const evidence: string[] = [];
 90→
 91→  // Deterministic: gather external signals (commits, CI)
 92→  const signalsResult = await gatherTaskSignals(surreal, taskId);
 93→  evidence.push(`Commits found: ${signalsResult.hasCommits}`);
 94→  evidence.push(`Signal count: ${signalsResult.signals.length}`);
 95→
 96→  const deterministicResult = compareTaskCompletion(signalsResult);
 97→  evidence.push(`Verdict: ${deterministicResult.verdict}`);
 98→  evidence.push(deterministicResult.text);
 99→
100→  // LLM reasoning path
101→  if (observerModel) {
102→    const skipDeterministic = await loadWorkspaceSkipSetting(surreal, workspaceRecord);
103→
104→    if (shouldSkipLlm(deterministicResult, skipDeterministic)) {
105→      logInfo("observer.llm.skip", "LLM skipped: deterministic match + CI passing", { taskId });
106→    } else {
107→      const context = await buildEntityContext(surreal, workspaceRecord, "task", taskId, body);
108→
109→      // Only invoke LLM when there are decisions to check against.
110→      // Without decisions, semantic verification has nothing to compare --
111→      // the deterministic CI-based verdict should stand.
112→      if (context.relatedDecisions.length === 0) {
113→        logInfo("observer.llm.skip", "LLM skipped: no related decisions to verify against", { taskId });
114→        await persistObservation(surreal, workspaceRecord, taskRecord, deterministicResult);
115→        return {
116→          observations_created: 1,
117→          verdict: deterministicResult.verdict,
118→          evidence,
119→        };
120→      }
121→
122→      const llmVerdict = await generateVerificationVerdict(observerModel, context, deterministicResult);
123→      const finalVerdict = applyLlmVerdict(deterministicResult, llmVerdict);
124→
125→      // Link contradicted decisions via observes edges
126→      const additionalRecords = extractDecisionRecords(llmVerdict?.evidence_refs);
127→
128→      await persistObservation(surreal, workspaceRecord, taskRecord, finalVerdict, "none", additionalRecords);
129→
130→      return {
131→        observations_created: 1,
132→        verdict: finalVerdict.verdict,
133→        evidence,
134→      };
135→    }
136→  }
137→
138→  // Deterministic-only path
139→  await persistObservation(surreal, workspaceRecord, taskRecord, deterministicResult);
140→
141→  return {
142→    observations_created: 1,
143→    verdict: deterministicResult.verdict,
144→    evidence,
145→  };
146→}
147→
148→// ---------------------------------------------------------------------------
149→// Intent verification (deterministic only)
150→// ---------------------------------------------------------------------------
151→
152→async function verifyIntent(input: ObserverAgentInput): Promise<ObserverAgentOutput> {
153→  const { surreal, workspaceRecord, entityId: intentId, entityBody: body } = input;
154→  const intentRecord = new RecordId("intent", intentId);
155→
156→  const intentSignals = await gatherIntentSignals(surreal, intentId, body);
157→  const result = compareIntentCompletion(intentSignals);
158→
159→  await persistObservation(surreal, workspaceRecord, intentRecord, result);
160→
161→  return {
162→    observations_created: 1,
163→    verdict: result.verdict,
164→    evidence: [result.text],
165→  };
166→}
167→
168→// ---------------------------------------------------------------------------
169→// Commit verification (deterministic only)
170→// ---------------------------------------------------------------------------
171→
172→async function verifyCommit(input: ObserverAgentInput): Promise<ObserverAgentOutput> {
173→  const { surreal, workspaceRecord, entityId: commitId, entityBody: body } = input;
174→  const commitRecord = new RecordId("git_commit", commitId);
175→
176→  const sha = (body?.sha as string) ?? "";
177→  const repository = (body?.repository as string) ?? "";
178→
179→  const signal = await checkCiStatus({ id: commitRecord, sha, repository });
180→  const result = compareCommitStatus({ signals: [signal], hasCommits: true });
181→
182→  await persistObservation(surreal, workspaceRecord, commitRecord, result);
183→
184→  return {
185→    observations_created: 1,
186→    verdict: result.verdict,
187→    evidence: [result.text],
188→  };
189→}
190→
191→// ---------------------------------------------------------------------------
192→// Decision verification (deterministic + LLM check against completed tasks)
193→// ---------------------------------------------------------------------------
194→
195→async function verifyDecision(input: ObserverAgentInput): Promise<ObserverAgentOutput> {
196→  const { surreal, workspaceRecord, entityId: decisionId, entityBody: body, observerModel } = input;
197→  const decisionRecord = new RecordId("decision", decisionId);
198→
199→  // Skip initial CREATE events — only verify status transitions
200→  if (!body?.updated_at) {
201→    logInfo("observer.decision.skipped_create", "Skipping decision CREATE event", { decisionId });
202→    return { observations_created: 0, verdict: "inconclusive", evidence: ["Skipped: CREATE event"] };
203→  }
204→
205→  const decisionSignals = await gatherDecisionSignals(surreal, workspaceRecord, body);
206→  const deterministicResult = compareDecisionConfirmation(decisionSignals);
207→
208→  await persistObservation(surreal, workspaceRecord, decisionRecord, deterministicResult);
209→  let observationsCreated = 1;
210→
211→  // LLM: when decision confirmed, check completed tasks against it (concurrent)
212→  if (observerModel && body?.status === "confirmed" && decisionSignals.completedTaskCount > 0) {
213→    const completedTasks = await queryCompletedTasks(surreal, workspaceRecord);
214→
215→    // Build contexts concurrently, then run LLM calls concurrently
216→    const taskContexts = await Promise.all(
217→      completedTasks.map(async (task) => {
218→        const taskId = task.id.id as string;
219→        const taskBody = { title: task.title, description: task.description, status: "completed" };
220→        const context = await buildEntityContext(surreal, workspaceRecord, "task", taskId, taskBody);
221→        return { task, taskId, context };
222→      }),
223→    );
224→
225→    const verdicts = await Promise.allSettled(
226→      taskContexts.map(({ context }) =>
227→        generateVerificationVerdict(observerModel, context, deterministicResult),
228→      ),
229→    );
230→
231→    for (let i = 0; i < verdicts.length; i++) {
232→      const settled = verdicts[i];
233→      if (settled.status === "rejected") {
234→        logInfo("observer.llm.error", "LLM verification failed for task", {
235→          taskId: taskContexts[i].taskId,
236→          error: String(settled.reason),
237→        });
238→        continue;
239→      }
240→
241→      const llmVerdict = settled.value;
242→      if (!llmVerdict || llmVerdict.verdict !== "mismatch") continue;
243→
244→      const finalVerdict = applyLlmVerdict(deterministicResult, llmVerdict);
245→      const taskRecord = new RecordId("task", taskContexts[i].taskId) as ObserveTargetRecord;
246→
247→      await persistObservation(surreal, workspaceRecord, decisionRecord, finalVerdict, "none", [taskRecord]);
248→      observationsCreated += 1;
249→    }
250→  }
251→
252→  return {
253→    observations_created: observationsCreated,
254→    verdict: deterministicResult.verdict,
255→    evidence: [deterministicResult.text],
256→  };
257→}
258→
259→// ---------------------------------------------------------------------------
260→// Observation peer review (deterministic + LLM)
261→// ---------------------------------------------------------------------------
262→
263→async function peerReviewObservation(input: ObserverAgentInput): Promise<ObserverAgentOutput> {
264→  const { surreal, workspaceRecord, entityId: observationId, entityBody: body, observerModel } = input;
265→  const observationRecord = new RecordId("observation", observationId);
266→
267→  const peerReviewSignals = await gatherPeerReviewSignals(surreal, workspaceRecord, body);
268→  const deterministicResult = compareObservationPeerReview(peerReviewSignals);
269→
270→  // LLM peer review when model available and observation has linked entities
271→  if (observerModel) {
272→    const linkedEntities = await loadObservationLinkedEntities(surreal, observationId);
273→
274→    if (linkedEntities.length > 0) {
275→      const llmVerdict = await generatePeerReviewVerdict(
276→        observerModel,
277→        peerReviewSignals.originalText,
278→        peerReviewSignals.originalSeverity,
279→        peerReviewSignals.sourceAgent,
280→        linkedEntities,
281→      );
282→
283→      if (llmVerdict) {
284→        const severity = llmVerdict.verdict === "unsupported" ? "warning" as const
285→          : "info" as const;
286→
287→        const reviewResult: VerificationResult = {
288→          verdict: llmVerdict.verdict === "sound" ? "match" : llmVerdict.verdict === "unsupported" ? "mismatch" : "inconclusive",
289→          severity,
290→          verified: llmVerdict.verdict === "sound",
291→          text: llmVerdict.reasoning,
292→          source: "llm",
293→          confidence: llmVerdict.confidence,
294→          observationType: "validation",
295→        };
296→
297→        await persistObservation(surreal, workspaceRecord, observationRecord, reviewResult, "llm");
298→
299→        return {
300→          observations_created: 1,
301→          verdict: reviewResult.verdict,
302→          evidence: [reviewResult.text],
303→        };
304→      }
305→
306→      logInfo("observer.llm.fallback", "LLM peer review failed, using deterministic", { observationId });
307→    } else {
308→      logInfo("observer.llm.skip", "LLM peer review skipped: no linked entities", { observationId });
309→    }
310→  }
311→
312→  // Deterministic fallback
313→  await persistObservation(surreal, workspaceRecord, observationRecord, deterministicResult, "peer_review");
314→
315→  return {
316→    observations_created: 1,
317→    verdict: deterministicResult.verdict,
318→    evidence: [deterministicResult.text],
319→  };
320→}
