322→// ---------------------------------------------------------------------------
323→// Signal gathering
324→// ---------------------------------------------------------------------------
325→
326→async function gatherIntentSignals(
327→  surreal: Surreal,
328→  intentId: string,
329→  body?: Record<string, unknown>,
330→): Promise<IntentSignals> {
331→  const status = (body?.status as string) ?? "unknown";
332→  const goal = (body?.goal as string) ?? "Unknown intent";
333→
334→  const intentRecord = new RecordId("intent", intentId);
335→  const [traceRows] = await surreal.query<[Array<{ trace_id?: RecordId }>]>(
336→    `SELECT trace_id FROM $intent;`,
337→    { intent: intentRecord },
338→  );
339→
340→  return { status, goal, hasTrace: !!traceRows?.[0]?.trace_id };
341→}
342→
343→async function gatherDecisionSignals(
344→  surreal: Surreal,
345→  workspaceRecord: RecordId<"workspace", string>,
346→  body?: Record<string, unknown>,
347→): Promise<DecisionSignals> {
348→  const status = (body?.status as string) ?? "unknown";
349→  const summary = (body?.summary as string) ?? "Unknown decision";
350→
351→  const [taskRows] = await surreal.query<[Array<{ count: number }>]>(
352→    `SELECT count() AS count FROM task WHERE workspace = $ws AND (status = "completed" OR status = "done") GROUP ALL;`,
353→    { ws: workspaceRecord },
354→  );
355→
356→  return { status, summary, completedTaskCount: taskRows?.[0]?.count ?? 0 };
357→}
358→
359→async function gatherPeerReviewSignals(
360→  surreal: Surreal,
361→  workspaceRecord: RecordId<"workspace", string>,
362→  body?: Record<string, unknown>,
363→): Promise<ObservationPeerReviewSignals> {
364→  const originalText = (body?.text as string) ?? "Unknown observation";
365→  const originalSeverity = ((body?.severity as string) ?? "info") as "info" | "warning" | "conflict";
366→  const sourceAgent = (body?.source_agent as string) ?? "unknown_agent";
367→
368→  const [taskRows] = await surreal.query<[Array<{ count: number }>]>(
369→    `SELECT count() AS count FROM task WHERE workspace = $ws GROUP ALL;`,
370→    { ws: workspaceRecord },
371→  );
372→  const [decisionRows] = await surreal.query<[Array<{ count: number }>]>(
373→    `SELECT count() AS count FROM decision WHERE workspace = $ws GROUP ALL;`,
374→    { ws: workspaceRecord },
375→  );
376→
377→  return {
378→    originalText,
379→    originalSeverity,
380→    sourceAgent,
381→    relatedTaskCount: taskRows?.[0]?.count ?? 0,
382→    relatedDecisionCount: decisionRows?.[0]?.count ?? 0,
383→  };
384→}
