460→
461→function extractDecisionRecords(evidenceRefs?: string[]): ObserveTargetRecord[] {
462→  if (!evidenceRefs) return [];
463→  const records: ObserveTargetRecord[] = [];
464→  for (const ref of evidenceRefs) {
465→    const parsed = parseEntityRef(ref);
466→    if (parsed && parsed.table === "decision") {
467→      records.push(new RecordId("decision", parsed.id) as ObserveTargetRecord);
468→    }
469→  }
470→  return records;
471→}
