577→/**
578→ * Creates a simple mock HTTP server that responds to GitHub-like API paths.
579→ * Returns a cleanup function to stop the server.
580→ */
581→export function createMockGitHubServer(
582→  responses: MockGitHubResponse[],
583→): { url: string; stop: () => void } {
584→  const responseMap = new Map<string, { status: number; body: unknown }>();
585→  for (const r of responses) {
586→    responseMap.set(r.path, { status: r.status, body: r.body });
587→  }
588→
589→  const server = Bun.serve({
590→    port: 0,
591→    fetch(req) {
592→      const url = new URL(req.url);
593→      const match = responseMap.get(url.pathname);
594→      if (match) {
595→        return new Response(JSON.stringify(match.body), {
596→          status: match.status,
597→          headers: { "Content-Type": "application/json" },
598→        });
599→      }
600→      return new Response(JSON.stringify({ message: "Not Found" }), { status: 404 });
601→    },
602→  });
603→
604→  return {
605→    url: `http://127.0.0.1:${server.port}`,
606→    stop: () => server.stop(true),
607→  };
608→}
