483→/**
484→ * Polls for an observation linked to a given entity via the observes edge.
485→ * Returns when at least one observation is found, or throws on timeout.
486→ */
487→export async function waitForObservation(
488→  surreal: Surreal,
489→  entityTable: string,
490→  entityId: string,
491→  timeoutMs = 15_000,
492→): Promise<ObservationRecord[]> {
493→  const start = Date.now();
494→
495→  while (Date.now() - start < timeoutMs) {
496→    const observations = await getObservationsForEntity(surreal, entityTable, entityId);
497→    if (observations.length > 0) {
498→      return observations;
499→    }
500→    await Bun.sleep(250);
501→  }
502→
503→  throw new Error(
504→    `No observation found for ${entityTable}:${entityId} within ${timeoutMs}ms`,
505→  );
506→}
507→
508→/**
509→ * Queries all observations linked to an entity via the observes edge.
510→ */
511→export async function getObservationsForEntity(
512→  surreal: Surreal,
513→  entityTable: string,
514→  entityId: string,
515→): Promise<ObservationRecord[]> {
516→  const entityRecord = new RecordId(entityTable, entityId);
517→
518→  // Query via reverse traversal from the entity through observes edges
519→  const reverseRows = (await surreal.query(
520→    `SELECT <-observes<-observation AS obs FROM $entity;`,
521→    { entity: entityRecord },
522→  )) as Array<Array<{ obs: RecordId[] }>>;
523→
524→  const obsIds = reverseRows[0]?.[0]?.obs ?? [];
525→  if (obsIds.length === 0) return [];
526→
527→  const allObs = (await surreal.query(
528→    `SELECT * FROM observation WHERE id IN $ids;`,
529→    { ids: obsIds },
530→  )) as Array<ObservationRecord[]>;
531→
532→  return allObs[0] ?? [];
533→}
