/**
 * Zod schemas for LLM structured output in observer reasoning pipelines.
 *
 * Pure module — no IO imports. Schemas constrain generateObject JSON output.
 */

import { z } from "zod";

// ---------------------------------------------------------------------------
// Verification verdict (semantic verification pipeline)
// ---------------------------------------------------------------------------

export const llmVerdictSchema = z.object({
  verdict: z.enum(["match", "mismatch", "inconclusive"]).describe(
    "match = entity aligns with decisions, mismatch = contradiction detected, inconclusive = insufficient evidence",
  ),
  confidence: z.number().min(0).max(1).describe(
    "Confidence in the verdict (0.0-1.0). Use <0.5 when evidence is ambiguous.",
  ),
  reasoning: z.string().describe(
    "Natural language explanation of the verdict. Reference specific entities and decisions.",
  ),
  evidence_refs: z.array(z.string()).describe(
    "Entity references in table:id format (e.g. decision:uuid, task:uuid) that support the verdict. Only include entities you were given in context.",
  ),
  contradiction: z.object({
    claim: z.string().describe("What the entity claims or implements. Use 'none' when verdict is not mismatch."),
    reality: z.string().describe("What the decision or constraint requires. Use 'none' when verdict is not mismatch."),
  }).describe(
    "Describes the specific contradiction. Set both fields to 'none' when verdict is not mismatch.",
  ),
});

/** Parsed verdict with contradiction normalized to undefined when not a mismatch. */
export type LlmVerdict = Omit<z.infer<typeof llmVerdictSchema>, "contradiction"> & {
  contradiction?: { claim: string; reality: string };
};

/** Strip "none" sentinel from contradiction field after parsing. */
export function parseLlmVerdict(raw: z.infer<typeof llmVerdictSchema>): LlmVerdict {
  const { contradiction, ...rest } = raw;
  const isNone = contradiction.claim === "none" && contradiction.reality === "none";
  return isNone ? rest : { ...rest, contradiction };
}

// ---------------------------------------------------------------------------
// Synthesis pattern (pattern synthesis pipeline)
// ---------------------------------------------------------------------------

export const synthesisPatternSchema = z.object({
  pattern_name: z.enum([
    "bottleneck_decision",
    "cascade_block",
    "priority_drift",
    "stale_cluster",
    "contradiction_cluster",
  ]).describe(
    "bottleneck_decision = single decision blocking multiple tasks, cascade_block = chain of blocked items, priority_drift = priorities inconsistent with actions, stale_cluster = group of stale items in same area, contradiction_cluster = multiple contradictions sharing a root cause",
  ),
  description: z.string().describe(
    "Natural language synthesis explaining the pattern and its impact.",
  ),
  contributing_entities: z.array(z.string()).min(2).describe(
    "Entity references in table:id format that contribute to this pattern. Minimum 2 required.",
  ),
  severity: z.enum(["warning", "conflict"]).describe(
    "warning = potential risk, conflict = active contradiction requiring resolution",
  ),
  suggested_action: z.string().describe(
    "Recommended action to address the pattern.",
  ),
});

export type SynthesisPattern = z.infer<typeof synthesisPatternSchema>;

export const synthesisResultSchema = z.object({
  patterns: z.array(synthesisPatternSchema),
});

export type SynthesisResult = z.infer<typeof synthesisResultSchema>;

// ---------------------------------------------------------------------------
// Contradiction detection (graph scan pipeline)
// ---------------------------------------------------------------------------

export const detectedContradictionSchema = z.object({
  decision_ref: z.string().describe(
    "The contradicted decision in table:id format (e.g. decision:uuid). Must match an ID from the provided decisions.",
  ),
  task_ref: z.string().describe(
    "The contradicting task in table:id format (e.g. task:uuid). Must match an ID from the provided tasks.",
  ),
  reasoning: z.string().describe(
    "Concise explanation of why the task contradicts the decision.",
  ),
});

export type DetectedContradiction = z.infer<typeof detectedContradictionSchema>;

export const contradictionDetectionResultSchema = z.object({
  contradictions: z.array(detectedContradictionSchema).describe(
    "Pairs of (decision, task) where a completed task implements an approach that contradicts a confirmed decision. Only include clear contradictions, not minor differences.",
  ),
});

// ---------------------------------------------------------------------------
// Peer review verdict (peer review pipeline)
// ---------------------------------------------------------------------------

export const peerReviewVerdictSchema = z.object({
  verdict: z.enum(["sound", "questionable", "unsupported"]).describe(
    "sound = observation is well-grounded (>=0.7), questionable = partially supported (0.4-0.7), unsupported = lacks evidence (<0.4)",
  ),
  confidence: z.number().min(0).max(1).describe(
    "Confidence in the review verdict (0.0-1.0).",
  ),
  reasoning: z.string().describe(
    "Evidence evaluation explaining why the observation is or isn't well-grounded.",
  ),
});

export type PeerReviewVerdict = z.infer<typeof peerReviewVerdictSchema>;

/**
 * LLM synthesis: effect boundary for generateObject calls in pattern synthesis pipeline.
 *
 * Takes anomalies from deterministic graph scan and synthesizes named patterns.
 * Uses AbortSignal.timeout(10_000) for latency control.
 * Returns undefined on any failure.
 */

import { generateObject, type LanguageModel } from "ai";
import { logError, logInfo } from "../http/observability";
import { contradictionDetectionResultSchema, synthesisResultSchema, type DetectedContradiction, type SynthesisPattern } from "./schemas";

export type Anomaly = {
  type: "contradiction" | "stale_blocked" | "status_drift";
  text: string;
  entityId: string;
  entityTable: string;
};

/**
 * Synthesizes anomalies into named patterns via LLM.
 * Returns patterns with min 2 contributing entities, or undefined on failure.
 */
export async function synthesizePatterns(
  model: LanguageModel,
  anomalies: Anomaly[],
): Promise<SynthesisPattern[] | undefined> {
  if (anomalies.length === 0) return [];

  const start = Date.now();

  // Partition large workspaces: top 20 per type
  const partitioned = partitionAnomalies(anomalies, 20);

  try {
    const anomaliesText = partitioned.map((a) =>
      `- [${a.entityTable}:${a.entityId}] (${a.type}) ${a.text}`,
    ).join("\n");

    const result = await generateObject({
      model,
      schema: synthesisResultSchema,
      prompt: `You are a pattern synthesis agent analyzing workspace anomalies to identify systemic patterns.

## Anomalies Detected
${anomaliesText}

## Instructions
Analyze these anomalies and identify higher-level patterns:
- "bottleneck_decision" = single decision blocking multiple tasks
- "cascade_block" = chain of blocked items
- "priority_drift" = priorities inconsistent with actions
- "stale_cluster" = group of stale items in same area
- "contradiction_cluster" = multiple contradictions sharing a root cause

Rules:
- Each pattern MUST reference at least 2 contributing entities using table:id format
- Only include entities from the anomalies listed above
- If no meaningful patterns emerge, return an empty patterns array
- Set severity to "conflict" only for active contradictions`,
      abortSignal: AbortSignal.timeout(10_000),
    });

    const latencyMs = Date.now() - start;
    logInfo("observer.llm.synthesis", "LLM pattern synthesis completed", {
      latencyMs,
      patternCount: result.object.patterns.length,
    });

    // Filter patterns with < 2 contributing entities (schema enforces min 2, but defense in depth)
    return result.object.patterns.filter((p) => p.contributing_entities.length >= 2);
  } catch (error) {
    const latencyMs = Date.now() - start;
    logError("observer.llm.synthesis_error", "LLM pattern synthesis failed", {
      error,
      latencyMs,
    });
    return undefined;
  }
}

// ---------------------------------------------------------------------------
// Contradiction detection (LLM-based)
// ---------------------------------------------------------------------------

export type DecisionInput = {
  id: string;
  summary: string;
  rationale?: string;
};

export type TaskInput = {
  id: string;
  title: string;
  description?: string;
};

/**
 * Detects contradictions between confirmed decisions and completed tasks via LLM.
 * Returns detected contradiction pairs, or undefined on failure.
 */
export async function detectContradictions(
  model: LanguageModel,
  decisions: DecisionInput[],
  tasks: TaskInput[],
): Promise<DetectedContradiction[] | undefined> {
  if (decisions.length === 0 || tasks.length === 0) return [];

  const start = Date.now();

  try {
    const decisionsText = decisions.map((d) =>
      `- [decision:${d.id}] ${d.summary}${d.rationale ? ` (rationale: ${d.rationale})` : ""}`,
    ).join("\n");

    const tasksText = tasks.map((t) =>
      `- [task:${t.id}] ${t.title}${t.description ? ` — ${t.description}` : ""}`,
    ).join("\n");

    const result = await generateObject({
      model,
      schema: contradictionDetectionResultSchema,
      prompt: `You are an observer agent scanning a workspace knowledge graph for contradictions between confirmed decisions and completed tasks.

## Confirmed Decisions
${decisionsText}

## Completed Tasks
${tasksText}

## Instructions
Identify any completed task that contradicts a confirmed decision. A contradiction means the task implements an approach that directly conflicts with what the decision mandates.

Examples of contradictions:
- Decision mandates tRPC but task implements REST endpoints
- Decision requires TypeScript but task delivers JavaScript
- Decision specifies PostgreSQL but task sets up MongoDB
- Decision requires feature flags but task ships without them

Rules:
- Only flag clear, direct contradictions — not minor implementation variations
- Use the exact table:id format from the lists above for decision_ref and task_ref
- If no contradictions exist, return an empty array`,
      abortSignal: AbortSignal.timeout(10_000),
    });

    const latencyMs = Date.now() - start;
    logInfo("observer.llm.contradiction_detection", "LLM contradiction detection completed", {
      latencyMs,
      contradictionCount: result.object.contradictions.length,
    });

    return result.object.contradictions;
  } catch (error) {
    const latencyMs = Date.now() - start;
    logError("observer.llm.contradiction_detection_error", "LLM contradiction detection failed", {
      error,
      latencyMs,
    });
    return undefined;
  }
}

/**
 * Partitions anomalies by type and takes top N per type to manage LLM context size.
 */
function partitionAnomalies(anomalies: Anomaly[], maxPerType: number): Anomaly[] {
  if (anomalies.length <= maxPerType * 3) return anomalies;

  const byType = new Map<string, Anomaly[]>();
  for (const a of anomalies) {
    const list = byType.get(a.type) ?? [];
    list.push(a);
    byType.set(a.type, list);
  }

  const result: Anomaly[] = [];
  for (const [, list] of byType) {
    result.push(...list.slice(0, maxPerType));
  }
  return result;
}

