 55→    });
 56→  } catch (error) {
 57→    console.error("beforeAll setup failed:", error);
 58→    throw error;
 59→  }
 60→}, 120_000);
 61→
 62→afterAll(async () => {
 63→  await teardownEvalRuntime(runtime);
 64→}, 120_000);
 65→
 66→// ---------------------------------------------------------------------------
