100→    expectedConfidenceRange: [0.6, 1.0],
101→    expectedSeverity: "conflict",
102→    expectedReasoningAnchors: ["parameterized", "concatenation"],
103→    expectedFacts: "The task builds SQL queries via string concatenation, which contradicts the decision requiring parameterized statements and forbidding string concatenation in SQL.",
104→  },
