111→    expectedConfidenceRange: [0.6, 1.0],
112→    expectedSeverity: "conflict",
113→    expectedReasoningAnchors: ["xml", "json"],
114→    expectedFacts: "The task implements an XML export endpoint, which contradicts the decision that all API responses must use JSON format exclusively.",
115→  },
