120→    evalType: "verification",
121→    scenario: "Task implements TypeScript middleware, decision requires TypeScript",
122→    seedCaseKey: "clear-match",
123→    expectedVerdict: "match",
124→    expectedConfidenceRange: [0.6, 1.0],
125→    expectedSeverity: "info",
126→    expectedReasoningAnchors: ["typescript"],
127→    expectedFacts: "The task implements authentication middleware in TypeScript, which aligns with the decision to use TypeScript for all backend services.",
