189→    expectedConfidenceRange: [0.6, 1.0],
190→    expectedSeverity: "info",
191→    expectedContradictionCount: 0,
192→    expectedFacts: "The LLM should detect no contradictions when a TypeScript task aligns with a TypeScript-only decision.",
193→  },
