200→    seedCaseKey: "detect-multi",
201→    expectedVerdict: "mismatch",
202→    expectedConfidenceRange: [0.6, 1.0],
203→    expectedSeverity: "conflict",
204→    expectedContradictionCount: 2,
205→    expectedContradictionPairs: [
206→      { decisionKey: "api-contradiction", taskKey: "api-contradiction" },
207→      { decisionKey: "security-contradiction", taskKey: "security-contradiction" },
208→    ],
209→    expectedFacts: "The LLM should detect both the REST-vs-tRPC contradiction and the string-concat-vs-parameterized-queries contradiction.",
210→  },
211→];
212→
213→// ---------------------------------------------------------------------------
214→// Task runner
215→// ---------------------------------------------------------------------------
216→
217→async function runObserverLlmCase(testCase: ObserverLlmTestCase): Promise<ObserverLlmEvalOutput> {
218→  try {
219→    if (testCase.evalType === "verification") {
220→      return await runVerificationCase(testCase);
221→    }
222→    if (testCase.evalType === "contradiction_detection") {
223→      return await runContradictionDetectionCase(testCase);
224→    }
225→    return await runPeerReviewCase(testCase);
226→  } catch (error) {
227→    return {
228→      caseId: testCase.id,
229→      verdict: "",
230→      reasoning: "",
231→      severity: "",
232→      evidenceRefs: [],
233→      success: false,
234→      error: error instanceof Error ? error.message : String(error),
235→    };
236→  }
237→}
238→
239→async function runVerificationCase(testCase: ObserverLlmTestCase): Promise<ObserverLlmEvalOutput> {
240→  const taskRecord = seedResult.tasks.get(testCase.seedCaseKey);
241→  if (!taskRecord) {
242→    throw new Error(`No seeded task for case key: ${testCase.seedCaseKey}`);
243→  }
244→
245→  const taskId = taskRecord.id as string;
246→
247→  // Build entity context (loads related decisions from graph)
248→  const context = await buildEntityContext(
249→    runtime.surreal,
250→    seedResult.workspaceRecord,
251→    "task",
252→    taskId,
253→  );
254→
255→  // Provide a minimal deterministic result for the LLM to enhance
256→  const deterministicResult = {
257→    verdict: "inconclusive" as const,
258→    severity: "info" as const,
259→    verified: false,
260→    text: "Deterministic check: no external signals available.",
261→  };
262→
263→  const llmVerdict = await generateVerificationVerdict(observerModel, context, deterministicResult);
264→  const finalVerdict = applyLlmVerdict(deterministicResult, llmVerdict);
265→
266→  return {
267→    caseId: testCase.id,
268→    verdict: finalVerdict.verdict,
269→    confidence: finalVerdict.confidence,
270→    reasoning: finalVerdict.text,
271→    severity: finalVerdict.severity,
272→    evidenceRefs: finalVerdict.evidenceRefs ?? [],
273→    success: true,
274→  };
275→}
276→
277→async function runPeerReviewCase(testCase: ObserverLlmTestCase): Promise<ObserverLlmEvalOutput> {
278→  const obsRecord = seedResult.observations.get(testCase.seedCaseKey);
279→  if (!obsRecord) {
280→    throw new Error(`No seeded observation for case key: ${testCase.seedCaseKey}`);
281→  }
282→
283→  const obsId = obsRecord.id as string;
284→
285→  // Load the observation details
286→  const [obsRows] = await runtime.surreal.query<[Array<{
287→    text: string;
288→    severity: string;
289→    source_agent: string;
290→  }>]>(
291→    `SELECT text, severity, source_agent FROM $obs;`,
292→    { obs: new RecordId("observation", obsId) },
293→  );
294→  const obs = obsRows?.[0];
295→  if (!obs) throw new Error(`Observation not found: ${obsId}`);
296→
297→  // Load linked entities via observes edges
298→  const [edgeRows] = await runtime.surreal.query<[Array<{ out: RecordId }>]>(
299→    `SELECT out FROM observes WHERE in = $obs;`,
300→    { obs: new RecordId("observation", obsId) },
301→  );
302→
303→  const linkedEntities: Array<{ table: string; id: string; title: string; description?: string }> = [];
304→  for (const row of edgeRows ?? []) {
305→    const targetTable = row.out.table.name;
306→    const targetId = row.out.id as string;
307→    const [details] = await runtime.surreal.query<[Array<{
308→      title?: string; summary?: string; text?: string; description?: string;
309→    }>]>(
310→      `SELECT title, summary, text, description FROM $record;`,
311→      { record: new RecordId(targetTable, targetId) },
312→    );
313→    const d = details?.[0];
314→    linkedEntities.push({
315→      table: targetTable,
316→      id: targetId,
317→      title: d?.title ?? d?.summary ?? d?.text ?? "Unknown",
318→      description: d?.description,
319→    });
320→  }
321→
322→  const llmVerdict = await generatePeerReviewVerdict(
323→    observerModel,
324→    obs.text,
325→    obs.severity,
326→    obs.source_agent,
327→    linkedEntities,
328→  );
329→
330→  if (!llmVerdict) {
331→    return {
332→      caseId: testCase.id,
333→      verdict: "inconclusive",
334→      reasoning: "LLM peer review failed",
335→      severity: "info",
336→      evidenceRefs: [],
337→      success: false,
338→      error: "LLM returned undefined",
339→    };
340→  }
341→
342→  return {
343→    caseId: testCase.id,
344→    verdict: llmVerdict.verdict === "sound" ? "match" : llmVerdict.verdict === "unsupported" ? "mismatch" : "inconclusive",
345→    confidence: llmVerdict.confidence,
346→    reasoning: llmVerdict.reasoning,
347→    severity: llmVerdict.verdict === "unsupported" ? "warning" : "info",
348→    evidenceRefs: [],
349→    success: true,
350→  };
351→}
352→
353→// ---------------------------------------------------------------------------
354→// Contradiction detection case subsets (keyed by seedCaseKey)
355→// ---------------------------------------------------------------------------
356→
357→const CONTRADICTION_DETECTION_SUBSETS: Record<string, {
358→  decisionKeys: string[];
359→  taskKeys: string[];
360→}> = {
361→  "detect-mixed": {
362→    decisionKeys: ["api-contradiction"],
363→    taskKeys: ["api-contradiction", "clear-match"],
364→  },
365→  "detect-clean": {
366→    decisionKeys: ["clear-match"],
367→    taskKeys: ["clear-match"],
368→  },
369→  "detect-multi": {
370→    decisionKeys: ["api-contradiction", "security-contradiction", "clear-match"],
371→    taskKeys: ["api-contradiction", "security-contradiction", "clear-match"],
372→  },
373→};
374→
375→async function runContradictionDetectionCase(testCase: ObserverLlmTestCase): Promise<ObserverLlmEvalOutput> {
376→  const subset = CONTRADICTION_DETECTION_SUBSETS[testCase.seedCaseKey];
377→  if (!subset) {
378→    throw new Error(`No contradiction detection subset for case key: ${testCase.seedCaseKey}`);
379→  }
380→
381→  const decisions = subset.decisionKeys.map((key) => {
382→    const record = seedResult.decisions.get(key);
383→    if (!record) throw new Error(`No seeded decision for key: ${key}`);
384→    return record;
385→  });
386→
387→  const tasks = subset.taskKeys.map((key) => {
388→    const record = seedResult.tasks.get(key);
389→    if (!record) throw new Error(`No seeded task for key: ${key}`);
390→    return record;
391→  });
392→
393→  // Load decision summaries and task titles from DB
394→  const decisionInputs = await Promise.all(decisions.map(async (decRecord) => {
395→    const [rows] = await runtime.surreal.query<[Array<{ summary: string; rationale?: string }>]>(
396→      `SELECT summary, rationale FROM $record;`,
397→      { record: decRecord },
398→    );
399→    return { id: decRecord.id as string, summary: rows[0].summary, rationale: rows[0].rationale };
400→  }));
401→
402→  const taskInputs = await Promise.all(tasks.map(async (taskRecord) => {
403→    const [rows] = await runtime.surreal.query<[Array<{ title: string; description?: string }>]>(
404→      `SELECT title, description FROM $record;`,
405→      { record: taskRecord },
406→    );
407→    return { id: taskRecord.id as string, title: rows[0].title, description: rows[0].description };
408→  }));
409→
410→  const detected = await detectContradictions(observerModel, decisionInputs, taskInputs);
411→
412→  if (!detected) {
413→    return {
414→      caseId: testCase.id,
415→      verdict: "inconclusive",
416→      reasoning: "LLM contradiction detection failed (returned undefined)",
417→      severity: "info",
418→      evidenceRefs: [],
419→      success: false,
420→      error: "LLM returned undefined",
421→    };
422→  }
423→
424→  const contradictionCount = detected.length;
425→  const expectedCount = testCase.expectedContradictionCount ?? 0;
426→  const countMatches = contradictionCount === expectedCount;
427→
428→  // Check if expected pairs were found
429→  let pairsMatch = true;
430→  if (testCase.expectedContradictionPairs) {
431→    for (const expected of testCase.expectedContradictionPairs) {
432→      const expectedDecId = seedResult.decisions.get(expected.decisionKey)?.id as string;
433→      const expectedTaskId = seedResult.tasks.get(expected.taskKey)?.id as string;
434→      const found = detected.some((c) =>
435→        c.decision_ref.includes(expectedDecId) && c.task_ref.includes(expectedTaskId),
436→      );
437→      if (!found) pairsMatch = false;
438→    }
439→  }
440→
441→  const reasoning = detected.map((c) => c.reasoning).join("; ") || "No contradictions found";
442→
443→  return {
444→    caseId: testCase.id,
445→    verdict: countMatches && pairsMatch
446→      ? (contradictionCount > 0 ? "mismatch" : "match")
447→      : "inconclusive",
448→    confidence: countMatches && pairsMatch ? 0.9 : 0.3,
449→    reasoning,
450→    severity: contradictionCount > 0 ? "conflict" : "info",
451→    evidenceRefs: detected.flatMap((c) => [c.decision_ref, c.task_ref]),
452→    success: true,
453→  };
454→}
455→
456→// ---------------------------------------------------------------------------
457→// Eval definition
458→// ---------------------------------------------------------------------------
459→
460→evalite<ObserverLlmTestCase, ObserverLlmEvalOutput, ObserverLlmTestCase>(
461→  "Observer LLM Reasoning Quality",
462→  {
463→    data: cases.map((testCase) => ({ input: testCase, expected: testCase })),
464→    task: async (input) => runObserverLlmCase(input),
465→    scorers: [
466→      {
467→        name: "verdict-accuracy",
468→        description: "Does the LLM verdict match the expected outcome (match/mismatch/inconclusive)?",
469→        scorer: verdictAccuracyScorer,
470→      },
471→      {
472→        name: "confidence-calibration",
473→        description: "Is the confidence score appropriate for the scenario clarity?",
474→        scorer: confidenceCalibrationScorer,
475→      },
476→      {
477→        name: "reasoning-quality",
478→        description: "Does the reasoning text reference relevant entities and decisions?",
479→        scorer: reasoningQualityScorer,
480→      },
481→      {
482→        name: "no-hallucination",
483→        description: "Reasoning does not contain forbidden patterns",
484→        scorer: ({ output, expected }) => {
485→          if (!expected?.forbiddenReasoningPatterns || expected.forbiddenReasoningPatterns.length === 0) return 1;
486→          if (!output.reasoning) return 1;
487→          const lowerReasoning = output.reasoning.toLowerCase();
488→          const violations = expected.forbiddenReasoningPatterns.filter((p) =>
489→            lowerReasoning.includes(p.toLowerCase()),
490→          );
491→          return violations.length === 0 ? 1 : 0;
492→        },
493→      },
494→      {
495→        name: "factuality",
496→        description: "LLM judge: is reasoning factually consistent with ground truth?",
497→        scorer: async ({ output, expected }) => {
498→          if (!expected?.expectedFacts || !output.success) return 1;
499→          const result = await Factuality({
500→            input: expected.scenario,
501→            output: output.reasoning,
502→            expected: expected.expectedFacts,
503→          });
504→          const score = result.score ?? 0;
505→          return score >= 0.4 ? 1 : 0;
506→        },
507→      },
508→    ],
509→    columns: ({ input, output, scores }) => [
510→      { label: "Model", value: observerModelId },
511→      { label: "Case", value: input.id },
512→      { label: "Type", value: input.evalType },
513→      { label: "Success", value: output.success ? "yes" : "no" },
514→      { label: "Verdict", value: formatScore(scores, "verdict-accuracy") },
515→      { label: "Confid", value: formatScore(scores, "confidence-calibration") },
516→      { label: "Reason", value: formatScore(scores, "reasoning-quality") },
517→      { label: "NoHalluc", value: formatScore(scores, "no-hallucination") },
518→      { label: "Factual", value: formatScore(scores, "factuality") },
519→    ],
520→  },
521→);
522→
523→function formatScore(scores: Array<{ name: string; score: number | null }>, name: string): string {
524→  const match = scores.find((s) => s.name === name);
525→  return match?.score !== null && match?.score !== undefined ? match.score.toFixed(2) : "N/A";
526→}
